content.content:
:root {
  /* ---- Ink (LeetCode text hierarchy) ---- */
  --color-ink: #262626;
  --color-ink-secondary: #595959;
  --color-ink-tertiary: #8c8c8c;
  --color-ink-disabled: #bfbfbf;

  /* ---- Surface ---- */
  --color-surface: #ffffff;
  --color-surface-elevated: #f7f8fa;
  --color-surface-subtle: #f0f0f0;
  --color-surface-hover: #ebebeb;

  /* ---- Navbar (dark LeetCode header) ---- */
  --color-nav: #1a1a1a;
  --color-nav-hover: #2a2a2a;
  --color-nav-active: #2a2a2a;
  --color-nav-text: #ffffff;
  --color-nav-text-secondary: #bfbfbf;

  /* ---- Border ---- */
  --color-border: #e5e5e5;
  --color-border-strong: #bfbfbf;

  /* ---- Accent (LeetCode-style) ---- */
  --color-accent: #2cbb5d;
  --color-accent-hover: #269f4e;
  --color-accent-subtle: #e6f7ed;
  --color-accent-pressed: #1e8a40;

  /* ---- Feedback ---- */
  --color-success: #2cbb5d;
  --color-success-subtle: #e6f7ed;
  --color-error: #ef4643;
  --color-error-subtle: #fdecea;
  --color-warning: #ffa116;
  --color-warning-subtle: #fff3e0;

  /* ---- Section tints (dots / lines only, LeetCode-adapted) ---- */
  --color-reading: #1890ff;
  --color-writing: #2cbb5d;
  --color-speaking: #ffa116;
  --color-listening: #722ed1;
  --color-toeic: #eb2f96;

  /* ---- Typography ---- */
  --font-sans:
    "Inter", -apple-system, BlinkMacSystemFont, "Segoe UI", "PingFang SC",
    "Hiragino Sans GB", "Microsoft YaHei", "Helvetica Neue", Helvetica, Arial,
    sans-serif;
  --font-mono:
    "Menlo", "SF Mono", "Cascadia Code", "JetBrains Mono", ui-monospace,
    monospace;

  --text-xs: 12px;
  --text-sm: 13px;
  --text-base: 14px;
  --text-lg: 16px;
  --text-xl: 18px;
  --text-2xl: 24px;
  --text-3xl: 30px;

  --font-normal: 400;
  --font-medium: 500;
  --font-semibold: 600;
  --font-bold: 700;

  --lh-tight: 1.3;
  --lh-normal: 1.5;
  --lh-relaxed: 1.7;

  /* ---- Spacing (4px grid, LeetCode-compact) ---- */
  --spacing-1: 4px;
  --spacing-2: 8px;
  --spacing-3: 12px;
  --spacing-4: 16px;
  --spacing-5: 20px;
  --spacing-6: 24px;
  --spacing-8: 32px;
  --spacing-10: 40px;
  --spacing-12: 48px;
  --spacing-16: 64px;

  /* ---- Radius ---- */
  --radius-sm: 4px;
  --radius: 6px;
  --radius-lg: 8px;
  --radius-xl: 12px;
  --radius-full: 9999px;

  /* ---- Shadow (minimal like LeetCode) ---- */
  --shadow-none: 0 0 0 0 transparent;
  --shadow-xs: 0 1px 2px rgba(0, 0, 0, 0.04);
  --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06);
  --shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  --shadow-md: 0 4px 16px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 8px 24px rgba(0, 0, 0, 0.12);
  --shadow-xl: 0 16px 48px rgba(0, 0, 0, 0.16);

  /* ---- Shadow colored ---- */
  --shadow-accent: 0 0 0 3px rgba(44, 187, 93, 0.2);
  --shadow-error: 0 0 0 3px rgba(239, 70, 67, 0.15);

  /* ---- Animation (LeetCode-crisp) ---- */
  --ease-out: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-in-out: cubic-bezier(0.65, 0, 0.35, 1);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
  --duration-fast: 100ms;
  --duration-base: 150ms;
  --duration-slow: 200ms;
  --duration-modal: 300ms;

  /* ---- Focus ring ---- */
  --focus-ring: 0 0 0 2px var(--color-surface), 0 0 0 4px var(--color-accent);

  /* ---- Layout ---- */
  --max-content: 860px;
  --header-height: 48px;

  /* ---- Legacy aliases ---- */
  --color-text: var(--color-ink);
  --color-text-muted: var(--color-ink-secondary);
  --color-background: var(--color-surface);
  --color-accent-dark: var(--color-accent-hover);
  --color-accent-light: var(--color-accent-subtle);
  --color-correct: var(--color-success);
  --color-correct-bg: var(--color-success-subtle);
  --color-incorrect: var(--color-error);
  --color-incorrect-bg: var(--color-error-subtle);
  --color-link: var(--color-accent);
  --font-body: var(--font-sans);
  --font-size-body: var(--text-base);
  --font-size-sm: var(--text-sm);
  --font-size-lg: var(--text-lg);
  --font-size-xl: var(--text-xl);
  --font-size-2xl: var(--text-2xl);
  --max-width: var(--max-content);

  /* Legacy spacing */
  --spacing-xs: var(--spacing-1);
  --spacing-sm: var(--spacing-2);
  --spacing-md: var(--spacing-4);
  --spacing-lg: var(--spacing-6);
  --spacing-xl: var(--spacing-8);
  --spacing-2xl: var(--spacing-12);
}

