import { useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import styles from "./AppShell.module.css";

interface AppShellProps {
  children: React.ReactNode;
}

export function AppShell({ children }: AppShellProps) {
  const location = useLocation();
  const navigate = useNavigate();
  const isToefl = location.pathname.startsWith("/toefl");
  const isToeic = location.pathname.startsWith("/toeic");
  const isShadowing = location.pathname.startsWith("/shadowing");

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === "d") {
        e.preventDefault();
        navigate("/dashboard");
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [navigate]);

  return (
    <div className={styles.shell}>
      <header className={styles.header}>
        <div className={styles.headerInner}>
          <Link to="/" className={styles.logo}>
            <span className={styles.logoMark}>ET</span>
            English Test Practice
          </Link>
          <nav className={styles.nav}>
            <Link
              to="/toefl"
              className={[
                styles.navLink,
                isToefl ? styles.navLinkActive : "",
              ].join(" ")}
            >
              TOEFL 2026
            </Link>
            <Link
              to="/toeic"
              className={[
                styles.navLink,
                isToeic ? styles.navLinkActive : "",
              ].join(" ")}
            >
              TOEIC L&amp;R
            </Link>
            <span className={styles.navDivider} />
            <Link
              to="/shadowing"
              className={[
                styles.navLink,
                isShadowing ? styles.navLinkActive : "",
              ].join(" ")}
            >
              Shadowing
            </Link>
            <span className={styles.navDivider} />
            <Link
              to="/dashboard"
              className={[
                styles.navLink,
                location.pathname === "/dashboard" ? styles.navLinkActive : "",
              ].join(" ")}
            >
              Dashboard
            </Link>
            <span className={styles.kbd}>
              <span className={styles.kbdKey}>⌘</span>
              <span className={styles.kbdKey}>D</span>
            </span>
          </nav>
        </div>
      </header>
      <main className={styles.main}>{children}</main>
    </div>
  );
}

.shell {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background: var(--color-surface-elevated);
}

.header {
  position: sticky;
  top: 0;
  z-index: 100;
  height: var(--header-height);
  background: var(--color-nav);
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
}

.headerInner {
  max-width: calc(var(--max-content) + var(--spacing-6) * 2);
  margin: 0 auto;
  padding: 0 var(--spacing-6);
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-4);
}

.logo {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-2);
  font-size: var(--text-base);
  font-weight: var(--font-semibold);
  color: #fff;
  text-decoration: none;
  white-space: nowrap;
  letter-spacing: -0.01em;
  transition: opacity var(--duration-fast) var(--ease-out);
}

.logo:hover {
  text-decoration: none;
  opacity: 0.85;
  color: #fff;
}

.logoMark {
  width: 22px;
  height: 22px;
  border-radius: var(--radius-sm);
  background: var(--color-accent);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-size: 11px;
  font-weight: var(--font-bold);
  flex-shrink: 0;
}

.nav {
  display: flex;
  align-items: center;
  gap: var(--spacing-1);
}

.navLink {
  display: inline-flex;
  align-items: center;
  height: 30px;
  padding: 0 12px;
  border-radius: var(--radius-sm);
  font-size: var(--text-sm);
  font-weight: var(--font-medium);
  color: var(--color-nav-text-secondary);
  text-decoration: none;
  transition:
    background var(--duration-fast) var(--ease-out),
    color var(--duration-fast) var(--ease-out);
  white-space: nowrap;
}

.navLink:hover {
  color: #fff;
  background: var(--color-nav-hover);
  text-decoration: none;
}

.navLinkActive {
  background: var(--color-accent);
  color: #fff;
}

.navLinkActive:hover {
  background: var(--color-accent-hover);
  color: #fff;
}

.navDivider {
  width: 1px;
  height: 18px;
  background: rgba(255, 255, 255, 0.15);
  margin: 0 var(--spacing-1);
}

.kbd {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  font-family: var(--font-sans);
  font-size: 11px;
  font-weight: var(--font-medium);
  color: rgba(255, 255, 255, 0.35);
  letter-spacing: 0.02em;
}

.kbdKey {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 18px;
  height: 16px;
  padding: 0 3px;
  border-radius: 3px;
  border: 1px solid rgba(255, 255, 255, 0.15);
  background: transparent;
  font-family: var(--font-sans);
  font-size: 10px;
  font-weight: var(--font-semibold);
  color: rgba(255, 255, 255, 0.35);
  letter-spacing: 0;
}

.main {
  flex: 1;
  padding: var(--spacing-6) var(--spacing-6);
  max-width: calc(var(--max-content) + var(--spacing-6) * 2);
  margin: 0 auto;
  width: 100%;
}

@media (max-width: 600px) {
  .headerInner {
    padding: 0 var(--spacing-4);
  }

  .navLink {
    padding: 0 8px;
    font-size: var(--text-xs);
  }

  .main {
    padding: var(--spacing-4) var(--spacing-4);
  }

  .kbd {
    display: none;
  }
}

import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { Button } from "../components/ui/Button";
import { useScoreHistory } from "../hooks/useScoreHistory";
import { formatSecondsAsMmSs } from "../lib/time";
import table from "../components/ui/ProblemTable.module.css";
import styles from "./HomePage.module.css";

type TestItem = {
  title: string;
  subtitle: string;
  path: string;
};

const tests: TestItem[] = [
  {
    title: "TOEFL iBT 2026",
    subtitle: "Reading, Writing, Listening & Speaking — full practice",
    path: "/toefl",
  },
  {
    title: "TOEIC L&R",
    subtitle: "Parts 2-7 — Listening & Reading practice",
    path: "/toeic",
  },
  {
    title: "Shadowing Practice",
    subtitle: "Listen and repeat — improve pronunciation & fluency",
    path: "/shadowing",
  },
];

export function HomePage() {
  const navigate = useNavigate();
  const { getAll } = useScoreHistory();
  const [stats, setStats] = useState<{
    solved: number;
    accuracy: number;
    avgTime: string;
    streak: number;
  } | null>(null);

  useEffect(() => {
    getAll().then((entries) => {
      if (entries.length === 0) return;
      const solved = entries.length;
      const accuracy = Math.round(
        entries.reduce((s, e) => s + e.pct, 0) / solved,
      );
      const timed = entries.filter((e) => typeof e.elapsedSeconds === "number");
      const avgTime =
        timed.length > 0
          ? formatSecondsAsMmSs(
              Math.round(
                timed.reduce((s, e) => s + (e.elapsedSeconds ?? 0), 0) /
                  timed.length,
              ),
            )
          : "—";

      const dates = Array.from(
        new Set(entries.map((e) => new Date(e.date).toDateString())),
      ).sort((a, b) => new Date(b).getTime() - new Date(a).getTime());
      let streak = 0;
      const today = new Date().toDateString();
      const yesterday = new Date(Date.now() - 86400000).toDateString();
      let checkDate = dates[0] === today ? today : yesterday;
      for (const d of dates) {
        if (d === checkDate) {
          streak++;
          checkDate = new Date(
            new Date(checkDate).getTime() - 86400000,
          ).toDateString();
        } else {
          break;
        }
      }

      setStats({ solved, accuracy, avgTime, streak });
    });
  }, [getAll]);

  return (
    <div className={styles.page}>
      <div className={styles.hero}>
        <span className={styles.badge}>AI-Powered Practice</span>
        <h1 className={styles.title}>
          English Test <span className={styles.titleAccent}>Practice</span>
        </h1>
        <p className={styles.description}>
          Master the TOEFL iBT 2026 & TOEIC L&R with AI-generated questions. No
          sign-up required.
        </p>
        <div className={styles.quickStart}>
          <Button variant="accent" size="md" onClick={() => navigate("/toefl")}>
            Start Practicing
          </Button>
          <Button
            variant="secondary"
            size="md"
            onClick={() => navigate("/dashboard")}
          >
            View Dashboard
          </Button>
        </div>
      </div>

      {stats && (
        <div className={styles.statsBar}>
          <div className={styles.statChip}>
            <span className={styles.statChipLabel}>Solved</span>
            <span className={styles.statChipValue}>{stats.solved}</span>
          </div>
          <div className={styles.statChip}>
            <span className={styles.statChipLabel}>Accuracy</span>
            <span className={styles.statChipValue}>{stats.accuracy}%</span>
          </div>
          <div className={styles.statChip}>
            <span className={styles.statChipLabel}>Avg Time</span>
            <span className={styles.statChipValue}>{stats.avgTime}</span>
          </div>
          <div className={styles.statChip}>
            <span className={styles.statChipLabel}>Streak</span>
            <span className={styles.statChipValue}>{stats.streak}d</span>
          </div>
        </div>
      )}

      <div className={styles.studySection}>
        <h2 className={styles.sectionTitle}>
          Problem Sets
          <span className={styles.sectionCount}>{tests.length} available</span>
        </h2>
        <div className={table.container}>
          <div className={table.header}>
            <span>#</span>
            <span>Test</span>
          </div>
          {tests.map((test, i) => (
            <Link key={test.path} to={test.path} className={table.row}>
              <span className={table.statusCol}>
                {stats ? (
                  <span className={table.statusSolved}>✓</span>
                ) : (
                  <span className={table.statusNone}>{i + 1}</span>
                )}
              </span>
              <span className={table.titleCell}>
                {test.title}
                <div className={table.titleMeta}>{test.subtitle}</div>
              </span>
            </Link>
          ))}
        </div>
      </div>

      <p className={styles.note}>
        Generate questions with an AI agent and save them under{" "}
        <code>public/questions/</code>. Prompts in <code>public/prompts/</code>.
      </p>
    </div>
  );
}

